var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"유진아! 피해!","JPN":"シロコさん！　避けて！","ENG":"Eujin! Watch out!","TWN":"劉珍！躲開！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"콜록! 콜록!","JPN":"ゲホ、ゲホ！","ENG":"*Cough!* *Cough!*","TWN":"咳咳！咳咳！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L6_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"젠장, 이렇게 쓰러트려도 줄어들질 않잖아?","JPN":"くそ、いくら倒しても減らない！","ENG":"Damn it, they just keep on coming!","TWN":"該死，怎麼都打不完？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"떠들 시간에 총알 한발이라도 더 쏴!","JPN":"話す余裕があるなら一発でも撃て！","ENG":"Shoot one more bastard if you have time to talk!","TWN":"有時間抱怨不如再多開一槍！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"제이크! 이 멍청이는 어디서 뭘 하고 있는 거야?","JPN":"ジェイク！　あのバカはどこで何してるのよ？","ENG":"Jake?! Where’s this idiot fooling around?","TWN":"傑克！這傻瓜是在哪摸魚？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"적이 이렇게나 많은데?!","JPN":"こんなに敵が多いのに！！","ENG":"And just when there’re so many hostiles here!","TWN":"沒看到有這麼多敵人嗎？！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대령님은 적의 지휘관과 선두 부대 전체를 상대로 싸우고 계십니다!","JPN":"大佐は敵の指揮官と先鋒部隊全体を相手に戦っています！","ENG":"The Colonel is fighting the enemy commander and their entire vanguard!","TWN":"上校正在力抗敵軍的指揮官和先鋒部隊！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"적어도 후방을 포위한 적의 공세는 우리가 막아내야 해요!","JPN":"せめて後方を囲んだ敵の攻勢は私たちで食い止めないと！","ENG":"We must hold off at least the ones surrounding us from the back!","TWN":"我們至少要擋下包圍後方的敵人攻勢！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"막으라고 해도…… 저건 준 5종 침식체라고!","JPN":"食い止めろって言っても……あれは準第5種侵食体なのよ！","ENG":"Even if we want to... That’s a semi-Category 5 Corrupted Object!","TWN":"說得這麼容易……對方可是5類侵蝕體欸！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"저걸 어떻게 막아?!","JPN":"あれをどうやって食い止めるの！？","ENG":"How do we stop that?!","TWN":"是要怎麼擋啦？！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_HOWLING_03"},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"큭, 저건…… 화살?","JPN":"くっ、あれは……矢？","ENG":"What the... Is that an arrow?","TWN":"唔，那是……弓箭？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_SNIPER_FIRE_BIG"},{"id":"L19_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"괜찮으세요, 실비아 씨? 다치진 않으셨나요?","JPN":"シルビアさん、大丈夫ですか？　お怪我はありませんか？","ENG":"Sylvia, are you okay? Are you hurt anywhere?","TWN":"希爾維亞，你沒事吧？有受傷嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"적이 남아 있는데 한눈 팔지 말라고 그랬지!","JPN":"敵が残ってるのに何をよそ見してるの！","ENG":"I told you to pay attention when there’re enemies nearby!","TWN":"敵人都還在欸，誰准你分心的！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"죄, 죄송합니다!","JPN":"す、すみません！","ENG":"I-I'm sorry!","TWN":"是…對不起！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"지금 전장에서 5종 침식체에게 유효한 타격을 줄 수 있는 건 당신과 내 미스틸테인뿐이야!","JPN":"今戦場で第5種侵食体に有効なダメージを与えられるのは、あなたと私のミスティルテインだけなのよ！","ENG":"The only ones on this battlefield who are able to do effective damage to the Category 5 Corrupted Object are you and my Misteltein!","TWN":"現在能夠有效攻擊5類侵蝕體的就只有你和我的米斯特汀！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"그러니까 정신 똑바로 차려야 한다고!","JPN":"だからしっかりしなさい！","ENG":"Therefore, we need to focus!","TWN":"所以你給我專心一點！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아, 알겠어요! 정신 차리겠습니다!","JPN":"わ、わかりました！　しっかりします！","ENG":"Y-yes ma’am! I will focus!","TWN":"是，遵命！我會專心！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"목소리!","JPN":"声！","ENG":"Louder!","TWN":"聲音！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"정신! 차리겠습니다!","JPN":"しっかり！　します！","ENG":"YES MA’AM! I WILL FOCUS!","TWN":"我會！專心！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……이상하군요.","JPN":"……おかしいですね。","ENG":"...That’s strange.","TWN":"……真是奇怪。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"또 무슨 일이지? 난 지금 가르강튀아의 에너지를 회복하느라 바쁘네.","JPN":"また何だ？　私は今ガルガンティアのエネルギーの回復で忙しいんだ。","ENG":"What is it this time? I’m currently busy recharging Garguantia’s energy.","TWN":"又有什麼事？我現在正忙著恢復加爾剛迪亞的能量！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"빨리 출격하지 않으면 적의 고위 침식체를 상대할 자가 부족해.","JPN":"早く出撃しないと、敵の高位侵食体を相手する者が足りない。","ENG":"If I don’t deploy soon, we won’t have enough troops to face their high-tier Corrupted Objects.","TWN":"再不趕快出擊的話，對付高階侵蝕體的人會不夠！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"급한 일이 아니라면 조금 있다가 이야기하지.","JPN":"急用でないなら、少し後で話そう。","ENG":"If it’s not urgent, let’s talk about it later.","TWN":"沒什麼急事的話晚點再說吧！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어째서 적의 마왕들이 나타나지 않는 걸까요?","JPN":"どうして敵の魔王たちが現れないのでしょうか。","ENG":"Why are the Demon Lords not showing themselves?","TWN":"為什麼敵人的魔王沒有出現呢？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"뭐라고?","JPN":"なんだと？","ENG":"What?","TWN":"什麼意思？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이렇게 포위망을 구축한 이상 마왕들이 나선다면 우린 바로 무너질 겁니다.","JPN":"このように包囲網を築いた以上、魔王たちが出てくれば私たちはすぐにでも崩れるでしょう。","ENG":"With the enemy surrounding us like this, if the Demon Lords themselves enter the battle, our forces will start collapsing right away.","TWN":"他們將我們包圍起來後，只要魔王出馬，我們就會立刻兵敗如山倒。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런데 어째서 아직 아무도 나타나지 않고 이런 소모전을 계속하는 걸까요?","JPN":"なのにどうしていまだに誰も現れず、こんな消耗戦を続けてるのでしょうか？","ENG":"Then why is it that nobody is making an appearance and they continue this battle of attrition?","TWN":"但魔王卻都沒有出現，他們是打算進行消耗戰嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"자네들조차 마왕을 쓰러트린 적은 한 번도 없다고 하지 않았나.","JPN":"君たちでさえ魔王を倒したことは一度もないと言っただろう。","ENG":"Didn’t you say that not even the Old Administration has ever defeated a Demon Lord?","TWN":"你不是說過，就連你們也從來未打敗過魔王嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"직접 움직이기엔 무슨 제약이 있는 것 아닌가?","JPN":"直接動くには何かの制約があるのではないか？","ENG":"Perhaps they are restricted from taking direct action?","TWN":"會不會是有什麼限制，導致他們無法直接行動？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그렇지 않다면 이런 게임은 애초에 성립될 수도 없을 테니까.","JPN":"そうでないと、そもそもこのようなゲームは成り立たないはずだからな。","ENG":"Because if that’s not the case, this game wouldn’t have been established in the first place.","TWN":"若非如此，這個遊戲從一開始就不成立吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"틀린 말은 아닙니다. 게임 마스터가 아닌 마왕은 힘에 제한을 받게 되죠.","JPN":"間違ってはいません。ゲームマスターでない限り、魔王は力に制限を受けます。","ENG":"There is some merit to that theory. After all, the Demon Lords, who are not the Game Master, would receive limitations on their powers.","TWN":"你說的沒錯，魔王不是遊戲專家，他們確實在能力上有受限。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 그렇다고 해도 나타나지 않을 이유는 없습니다.","JPN":"しかし、そうだとしても現れない理由にはなりません。","ENG":"However, even if that’s true, there’s no reason for them not to show up.","TWN":"不過就算如此，也沒理由不出現。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니, 어쩌면…… 나타나지 않는 것이 아니라 나타나지 못하는 것일지도……","JPN":"いや、もしかしたら……現れないのではなく、現れることができないのかも……","ENG":"No, maybe... It’s not that they won’t appear, but they can’t...?","TWN":"還是……魔王不是不出現，而是無法出現……"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"중장님. 작전을 바꿔야겠습니다.","JPN":"中将。作戦を変えましょう。","ENG":"Lieutenant General, I would like to suggest a change of plans.","TWN":"中將，必須改變作戰方式！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"이 상황을 타개할 방책이 있나?","JPN":"この状況を打開する方法があるのか？","ENG":"Do you have a plan to break us out of this situation?","TWN":"你有方法可以改變現在的局勢嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지금까지는 델타 세븐의 방식대로 싸웠으니……","JPN":"今まではデルタセブンのやり方で戦ったので……","ENG":"Since we’ve been fighting in accordance with Delta Seven’s methods...","TWN":"目前為止都是用第七三角洲部隊的方式在作戰……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이제부터는 구 관리국의 방식을 한 번 써 보시죠.","JPN":"これからは旧管理局のやり方を使ってみましょう。","ENG":"Now we’ll try the Old Administration’s methods.","TWN":"接下來試試看舊管理局的方式吧！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};